import jwt
from jwt import PyJWKClient

def decode_jwt(token):
    try:
        # Using PyJWKClient for JWT verification in production environment
        # Replace with your Auth0 domain 
        key = PyJWKClient("https://<your-auth0-domain>.well-known/jwks.json")
        public_key = key.get_signing_key_from_jwt(token)
        decoded = jwt.decode(
            token, 
            public_key.to_pem(), 
            algorithms=['RS256'],
            options={"verify_exp": True}
        )
        
        return decoded
    except Exception as e:
        print("Error in JWT decoding : ", str(e))